class Solution:
    def escapeGhosts(self, ghosts: List[List[int]], target: List[int]) -> bool:
        d = abs(target[0]) + abs(target[1])
        return all(abs(g[0]-target[0]) + abs(g[1]-target[1]) > d for g in ghosts)

